import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"任务包","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/task-center/task-bundle.md","filePath":"zh-CN/rewards/task-center/task-bundle.md"}'),l={name:"rewards/task-center/task-bundle.md"};function i(n,t,s,p,d,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="任务包" tabindex="-1">任务包 <a class="header-anchor" href="#任务包" aria-label="Permalink to &quot;任务包&quot;">​</a></h1><p>任务包（也称&quot;挑战任务&quot;）是将多个相关任务打包成一个&quot;挑战&quot;的玩法。用户通过完成包内任务逐步解锁阶梯式奖励——完成的任务越多，获得的奖励越丰厚。任务包有独立的截止日期，需在有效期内完成。</p><h2 id="如何参与" tabindex="-1">如何参与 <a class="header-anchor" href="#如何参与" aria-label="Permalink to &quot;如何参与&quot;">​</a></h2><p>参与任务包需已登录账号，任务包在有效期内，且满足任务包的目标用户条件（如新用户专属包需为新注册用户）。</p><p>操作步骤：</p><ol><li>在任务中心找到对应任务包，查看包内任务列表</li><li>部分任务包需先点击&quot;领取&quot;按钮才能开始，领取后任务包倒计时启动</li><li>按任务要求完成各项操作（如开户、完成交易等）</li><li>每完成一个任务，对应阶梯奖励自动发放</li><li>完成全部任务后，系统弹窗提示最终完成奖励</li></ol><h2 id="状态说明" tabindex="-1">状态说明 <a class="header-anchor" href="#状态说明" aria-label="Permalink to &quot;状态说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td>进行中</td><td>任务包在有效期内，尚未完成全部任务（已达到的阶梯奖励会在此状态下自动发放）</td></tr><tr><td>已完成</td><td>包内所有任务均已完成</td></tr><tr><td>未完成</td><td>截止日期已过但未完成全部任务</td></tr></tbody></table><h2 id="任务包领取与进度答疑" tabindex="-1">任务包领取与进度答疑 <a class="header-anchor" href="#任务包领取与进度答疑" aria-label="Permalink to &quot;任务包领取与进度答疑&quot;">​</a></h2><p><strong>任务包是什么？</strong></p><p>任务包是把多个相关任务组合成一个挑战的功能。完成包内不同数量的任务可解锁不同档次的奖励，完成越多、奖励越好，类似&quot;闯关&quot;。</p><p><strong>任务包与普通任务有什么区别？</strong></p><p>普通任务单独完成、单独领奖。任务包是多个任务的集合，有统一的截止日期，奖励以&quot;阶梯&quot;形式发放，进度在任务包内单独计算，不与同类普通任务共享进度。</p><p><strong>如何参与任务包？</strong></p><p>在任务中心看到任务包后即可参与。部分任务包需先点击&quot;领取&quot;按钮才能开始，领取后任务包倒计时启动。具体以页面提示为准。参与后按照包内各任务的要求逐一完成即可。</p><p><strong>完成任务包内一个任务就能获得奖励吗？还是要全部完成？</strong></p><p>不需要全部完成才能得奖。只要达到某一阶梯要求的完成数量，对应奖励就会自动发放。例如完成 3 个任务解锁第一档奖励，完成 6<br> 个解锁第二档，以此类推。全部完成可获得最终奖励弹窗提示。</p><p><strong>阶梯奖励是什么意思？</strong></p><p>阶梯奖励是指按照任务完成数量分档次发放的奖励机制。不同档次对应不同奖励（如任务币、卡券等），完成数量越多、档次越高、奖励越丰厚。每个档次只发放一次，不重复计算。</p><p><strong>任务包内的任务过期了怎么办？</strong></p><p>任务包有独立截止日期，到期后任务包变为&quot;未完成&quot;状态，未达到的阶梯奖励将不再发放。已达到阶梯的奖励已自动发放，不受影响。建议在有效期内尽早完成各项任务。</p><p><strong>任务包有截止日期吗？</strong></p><p>有。每个任务包都有独立的截止日期，可在任务包详情页查看剩余时间。请务必在截止日期前完成任务，过期后无法继续参与。</p><p><strong>任务包完成后奖励多久到账？</strong></p><p>达到阶梯条件后奖励通常即时自动发放。若超过 24 小时仍未到账，请联系客服并提供账号信息。</p><p><strong>为什么我看不到任务包？</strong></p><p>可能原因：当前没有进行中的任务包活动、任务包针对特定用户群体（如新用户专属），不满足条件则不展示、任务包已过截止日期。如确认应有任务包但看不到，请联系客服核实。</p><p><strong>新用户任务包和普通任务包有什么区别？</strong></p><p>新用户任务包是专为新用户设计的专属挑战，通常包含引导完成开户、首次交易等核心操作的任务，帮助新用户快速熟悉平台。部分新用户任务包在首次入金后启动倒计时（如入金后<br> 30 天内完成），老用户不可见此任务包。普通任务包面向全体符合条件的用户开放。</p><p><strong>任务包的进度怎么查看？</strong></p><p>在任务中心进入任务包详情页，可以看到：当前已完成的任务数量、各阶梯的解锁情况、已发放的奖励记录，以及剩余截止时间。</p><p><strong>任务包内的任务进度和普通任务一样吗？</strong></p><p>不一样。任务包内的任务进度独立计算，与同类普通任务互不影响。即使普通任务已完成，也不会自动计入任务包的进度。</p><p><strong>阶梯奖励会重复发放吗？</strong></p><p>不会。每个阶梯的奖励只发放一次。达到该阶梯后奖励立即发放，之后即使任务数量增加也不会重复发同一档次的奖励。</p><h2 id="任务包领取与使用限制" tabindex="-1">任务包领取与使用限制 <a class="header-anchor" href="#任务包领取与使用限制" aria-label="Permalink to &quot;任务包领取与使用限制&quot;">​</a></h2><ul><li>任务包截止日期过后，&quot;进行中&quot;状态变为&quot;未完成&quot;，未解锁的阶梯不补发</li><li>已发放的阶梯奖励不受截止日期影响，不会被追回</li><li>任务包内任务进度与普通任务进度相互独立，需分别完成</li><li>新用户任务包仅对新用户展示，部分任务包在首次入金后开始倒计时（如 30 天内完成）</li><li>部分任务包针对特定用户群体，不满足条件的用户不会看到该任务包</li><li>完成全部任务后的弹窗提示仅为提示性质，奖励已在达到各阶梯时自动发放</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards/task-center/task-center">任务中心</a> — 任务系统</li><li><a href="/wiki/rewards/任务币">任务币</a> — 任务收益</li></ul><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/rewards">活动与奖励</a></li></ul>',41)])])}const q=a(l,[["render",i]]);export{c as __pageData,q as default};
